const death = actor?.system?.attributes?.death;
if (!death) return;

const name = actor.name;
const successes = death.success;
const failures = death.failure;

if (failures >= 3) {
  ui.notifications.error(`${name} has failed 3 death saves!`);
} else if (successes >= 3) {
  ui.notifications.info(`${name} has stabilised!`);
} else {
  ui.notifications.warn(`${name}: ${successes}/3 successes, ${failures}/3 failures`);
}
